    // ═════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝
    // END BASIC STAT FILTERS

    let diffATK = c.ATK;
    let diffDEF = c.DEF;
    let diffHP = c.HP;
    let diffSPD = c.SPD;
    let diffCD = c.CD;
    let diffCR = c.CR;
    let diffEHR = c.EHR;
    let diffRES = c.RES;
    let diffBE = c.BE;
    let diffERR = c.ERR;
    let diffOHB = c.OHB;

